window.bookmark={init:function(){window.addBookmark=()=>this.addBookmark()},addBookmark:function(){const t=window.getSelection(),e=t.toString().trim();e?(this.saveBookmark(e,`標記 "${e.substring(0,20)}..."`,window.scrollY),this.showNotification("📌 書籤已添加")):(this.saveBookmark("",`位置 ${Math.round(window.scrollY/100)}`,window.scrollY),this.showNotification("🔖 閱讀位置已保存"))},saveBookmark:function(e,t,n){const s=JSON.parse(localStorage.getItem("bookmarks")||"[]"),i=document.querySelector("article"),o=document.querySelector("h1")?.textContent||"未命名文章";s.push({id:Date.now(),text:e.substring(0,50)+(e.length>50?"...":""),name:t||`標記 ${s.length+1}`,position:n,url:window.location.pathname,articleTitle:o,date:(new Date).toLocaleString()}),localStorage.setItem("bookmarks",JSON.stringify(s)),console.log("書籤已儲存",s)},showNotification:function(e){const t=document.createElement("div");t.textContent=e,t.className="bookmark-notification",document.body.appendChild(t),setTimeout(()=>{t.remove()},2e3)},getAllBookmarks:function(){return JSON.parse(localStorage.getItem("bookmarks")||"[]")},deleteBookmark:function(e){let t=this.getAllBookmarks();t=t.filter(t=>t.id!==e),localStorage.setItem("bookmarks",JSON.stringify(t))},goToBookmark:function(e){e.url===window.location.pathname?window.scrollTo({top:e.position,behavior:"smooth"}):window.location.href=e.url+"#bookmark-"+e.id}}